const numbersToWords=J=>{const b=['','ένα','δύο','τρία','τέσσερα','πέντε','έξι','επτά','οκτώ','εννέα','δέκα','έντεκα','δώδεκα','δεκατρία','δεκατέσσερα','δεκαπέντε','δεκαέξι','δεκαεπτά','δεκαοκτώ','δεκαεννέα'];if(J<0x14)return b[J];if(J<0x64)return['','','είκοσι','τριάντα','σαράντα','πενήντα','εξήντα','εβδομήντα','ογδόντα','ενενήντα'][Math['floor'](J/0xa)]+(J%0xa?'\x20'+b[J%0xa]:'');if(J<0x3e8){const f=Math['floor'](J/0x64),U=J%0x64;return(0x1===f?'εκατό':0x2===f?'διακόσια':0x3===f?'τριακόσια':0x4===f?'τετρακόσια':0x5===f?'πεντακόσια':0x6===f?'εξακόσια':0x7===f?'επτακόσια':0x8===f?'οκτακόσια':0x9===f?'εννιακόσια':'')+(U?'\x20'+numbersToWords(U):'');}return J<0xf4240?numbersToWords(Math['floor'](J/0x3e8))+'\x20χιλιάδες'+(J%0x3e8?'\x20'+numbersToWords(J%0x3e8):''):numbersToWords(Math['floor'](J/0xf4240))+'\x20εκατομμύρια'+(J%0xf4240?'\x20'+numbersToWords(J%0xf4240):'');},numberToText=(J,b='money')=>{const f=Math['floor'](J),U=Math['round'](0x64*(J-f));let m=numbersToWords(f),l=U>0x0?numbersToWords(U):'';switch(b){case'money':return l?m+'\x20ευρώ\x20και\x20'+l+'\x20λεπτά':m+'\x20ευρώ';case'time':return l?m+'\x20ώρες\x20και\x20'+l+'\x20λεπτά':m+'\x20ώρες';default:return l?m+'\x20και\x20'+l:''+m;}};